To address the issue where the AlphaMissense score is not visible and the "No sgRNAs available" error persists despite valid parameters, I will update the application with the following changes:

1.  **Fix "No sgRNAs" Error**: I will modify the `findCas9Sites` function to dynamically calculate the search window based on the user's selected `oligoLength`. Previously, the window was fixed, which meant if you selected a long oligo to reach a distant PAM, the system wouldn't even look for that PAM, causing a false failure.
2.  **Fix AlphaMissense Visibility**: I will update the AlphaMissense component to display a "No Data Found" state instead of disappearing completely. Since the MyVariant.info database is primarily human-centric, searching for Yeast genes often returns no results. This change ensures you can see *where* the score would be (after the Gene Card) and understand why it might be missing.

# Updated files:

## services/crispr.ts

-   Updated `findCas9Sites` to accept `oligoLength`.
-   Changed the hardcoded `WINDOW` to a dynamic search radius derived from `oligoLength`, ensuring all potential PAM sites are discovered.

```typescript
import { Cas9Site, RepairResult } from '../types';
import { CODON_TABLE, codonToAA, reverseComplement, translate, generateSimpleAlignment } from './utils';

// Removed fixed WINDOW constant

export function findCas9Sites(geneSequence: string, aminoAcidPosition: number, oligoLength: number): Cas9Site[] {
  const nucleotidePosition = (aminoAcidPosition - 1) * 3;

  // Dynamic Window Calculation:
  // We need to look far enough to find any PAM that could theoretically be reached by the oligo.
  // If the oligo is 100bp, we might use a PAM ~90bp away if the mutation is at the very edge.
  // We use a safety factor (e.g., 1.5x oligoLength) to ensure we capture all relevant sites.
  const searchRadius = Math.ceil(oligoLength * 1.5);

  const start = Math.max(0, nucleotidePosition - searchRadius);
  const end = Math.min(geneSequence.length, nucleotidePosition + searchRadius);
  const region = geneSequence.substring(start, end);

  const sites: Cas9Site[] = [];

  // Forward: N(20)NGG
  const forwardRegex = /(?=([ACGT]{20}[ACGT]GG))/gi;
  let match;
  while ((match = forwardRegex.exec(region)) !== null) {
    sites.push({
      position: start + match.index,
      sequence: match[1],
      strand: 'forward'
    });
    forwardRegex.lastIndex = match.index + 1;
  }

  // Reverse: CC N(20)
  const reverseRegex = /(?=(CC[ACGT][ACGT]{20}))/gi;
  while ((match = reverseRegex.exec(region)) !== null) {
    sites.push({
      position: start + match.index,
      sequence: match[1],
      strand: 'reverse'
    });
    reverseRegex.lastIndex = match.index + 1;
  }

  // Sort by distance to mutation site
  return sites.sort((a, b) => {
    return Math.abs(a.position - nucleotidePosition) - Math.abs(b.position - nucleotidePosition);
  });
}

/**
 * Calculates a heuristic CRISPR efficiency score (0-100) based on established rules
 * (e.g. Doench 2014, Wang 2014, Graf 2019).
 * Robust for client-side calculation without heavy ML models.
 * @param guideWithPam 23nt sequence (20nt Spacer + NGG)
 */
function calculateEfficiencyScore(guideWithPam: string): number {
  const spacer = guideWithPam.substring(0, 20).toUpperCase();
  const pam = guideWithPam.substring(20, 23).toUpperCase();

  let score = 50; // Base score

  // 1. GC Content (Ideal 40-60%)
  // Extreme GC content is poor for PCR/binding efficiency.
  const gcCount = spacer.split('').filter(c => c === 'G' || c === 'C').length;
  const gcContent = gcCount / 20;

  if (gcContent >= 0.4 && gcContent <= 0.6) {
      score += 20;
  } else if (gcContent >= 0.3 && gcContent <= 0.8) {
      score += 10;
  } else {
      score -= 20;
  }

  // 2. Position 20 (Nucleotide immediately 5' of PAM) - Critical for Cas9 loading
  // G is highly favored, T is disfavored.
  const pos20 = spacer[19];
  if (pos20 === 'G') score += 15;
  else if (pos20 === 'C') score += 5;
  else if (pos20 === 'T') score -= 10; 

  // 3. Poly-T (Pol III Terminator)
  // 4 consecutive Ts terminate transcription from U6 promoters (standard for pML104)
  if (spacer.includes('TTTT')) {
      score -= 50; 
  }

  // 4. PAM Sequence Context (NGG)
  // CGG and TGG are often slightly more efficient than AGG/GGG in yeast.
  if (pam === 'CGG' || pam === 'TGG') score += 5;
  else if (pam === 'GGG') score -= 5;

  // 5. Seed Region Stability (Nucleotides 10-20)
  // Avoid T-rich seed regions which can lower Tm too much.
  const seed = spacer.substring(10);
  if (seed.split('T').length - 1 >= 4) {
      score -= 10;
  }

  // Clamp 0-100
  return Math.max(0, Math.min(100, score));
}

interface MutationAttempt {
    sequence: string[];
    mutated: boolean;
    strategy: 'PAM_SILENT' | 'SEED_SILENT' | null;
    mutationCount: number;
}

function mutatePam(
  homologyList: string[],
  strand: 'forward' | 'reverse',
  pamStart: number,
  homologyStart: number
): MutationAttempt {
  const pamPosInHomology = pamStart - homologyStart;
  const listCopy = [...homologyList];

  // Define critical indices (The GG of NGG or CC of CCN)
  const criticalIndices = strand === 'forward'
    ? [pamPosInHomology + 21, pamPosInHomology + 22]
    : [pamPosInHomology, pamPosInHomology + 1];

  const codonStarts = new Set<number>();
  criticalIndices.forEach(idx => {
    if (idx >= 0 && idx < listCopy.length) {
      codonStarts.add(Math.floor(idx / 3) * 3);
    }
  });

  const sortedCodonStarts = Array.from(codonStarts).sort((a, b) => a - b);

  let bestResult: MutationAttempt = { sequence: [], mutated: false, strategy: null, mutationCount: 0 };
  let minChanges = Infinity;

  for (const codonStart of sortedCodonStarts) {
    if (codonStart + 3 > listCopy.length) continue;

    const currentCodon = listCopy.slice(codonStart, codonStart + 3).join('').toUpperCase();
    const currentAA = codonToAA(currentCodon);
    if (!currentAA || currentAA === '*') continue;

    const synonymousCodons = CODON_TABLE[currentAA] || [];

    for (const synonym of synonymousCodons) {
      if (synonym === currentCodon) continue;
      if (codonToAA(synonym) !== currentAA) continue;

      let disrupts = false;
      let tempChanges = 0;

      for (let i = 0; i < 3; i++) {
        const pos = codonStart + i;
        if (criticalIndices.includes(pos)) {
            if (synonym[i] !== currentCodon[i]) {
                disrupts = true;
            }
        }
        if (synonym[i] !== currentCodon[i]) tempChanges++;
      }

      if (disrupts) {
        if (tempChanges < minChanges) {
             minChanges = tempChanges;
             const newList = [...homologyList];
             for (let i = 0; i < 3; i++) newList[codonStart + i] = synonym[i];
             bestResult = { sequence: newList, mutated: true, strategy: 'PAM_SILENT', mutationCount: tempChanges };
        }
      }
    }
  }

  return bestResult;
}

function mutateSeed(
  homologyList: string[],
  strand: 'forward' | 'reverse',
  pamStart: number,
  homologyStart: number
): MutationAttempt {
    const pamPosInHomology = pamStart - homologyStart;
    const listCopy = [...homologyList];

    // Seed: 10nt proximal to PAM
    const seedIndices = new Set<number>();
    if (strand === 'forward') {
        for(let i=10; i<=19; i++) seedIndices.add(pamPosInHomology + i);
    } else {
        for(let i=3; i<=12; i++) seedIndices.add(pamPosInHomology + i);
    }

    const codonStarts = new Set<number>();
    seedIndices.forEach(idx => {
         if(idx >= 0 && idx < listCopy.length) {
            codonStarts.add(Math.floor(idx/3)*3);
        }
    });

    const sortedCodonStarts = Array.from(codonStarts).sort((a,b)=>a-b);
    let totalMutations = 0;

    for (const codonStart of sortedCodonStarts) {
         if (codonStart + 3 > listCopy.length) continue;

         const currentCodon = listCopy.slice(codonStart, codonStart+3).join('').toUpperCase();
         const currentAA = codonToAA(currentCodon);
         if (!currentAA || currentAA === '*') continue;

         const synonyms = CODON_TABLE[currentAA] || [];

         let bestSynonym = null;
         let maxNewSeedChanges = 0;
         let bestTotalChanges = 0; 

         for (const synonym of synonyms) {
             if (synonym === currentCodon) continue;
             if (codonToAA(synonym) !== currentAA) continue;

             let seedChanges = 0;
             let totalChanges = 0;
             for(let i=0; i<3; i++) {
                 if (synonym[i] !== currentCodon[i]) {
                     totalChanges++;
                     if (seedIndices.has(codonStart + i)) {
                         seedChanges++;
                     }
                 }
             }

             if (seedChanges > maxNewSeedChanges) {
                 maxNewSeedChanges = seedChanges;
                 bestTotalChanges = totalChanges;
                 bestSynonym = synonym;
             }
         }

         if (bestSynonym && maxNewSeedChanges > 0) {
             for(let i=0; i<3; i++) listCopy[codonStart+i] = bestSynonym[i];
             totalMutations += bestTotalChanges; 
         }

         if (totalMutations >= 2) break; 
    }

    if (totalMutations >= 2) {
        return { sequence: listCopy, mutated: true, strategy: 'SEED_SILENT', mutationCount: totalMutations };
    }

    return { sequence: [], mutated: false, strategy: null, mutationCount: 0 };
}

export function generateRepairTemplates(
  geneSequence: string,
  cas9Sites: Cas9Site[],
  aminoAcidPosition: number,
  newAminoAcid: string,
  oligoLength: number = 75
): RepairResult[] {
  const results: RepairResult[] = [];
  const mutationPosition = (aminoAcidPosition - 1) * 3;

  for (const site of cas9Sites) {
    const pamStart = site.position;

    // Sliding Window Logic:
    // We need to find a window of 'oligoLength' that:
    // 1. Includes the mutation codon (mutationPosition to mutationPosition+2)
    // 2. Includes the critical PAM/Seed regions for the site (site.position area)
    // 3. Keeps the mutation as central as possible.

    // Identify critical region for this site (approximate):
    // For forward PAM silencing: PAM is at +20/21/22 relative to site start.
    // For reverse PAM silencing: PAM is at +0/1/2 relative to site start.
    // We just need to ensure the full site (sequence.length) + mutation is generally coverable.

    // Determine the absolute range we MUST cover.
    // Minimally, we need the mutation codon and the PAM sequence to attempt a silent mutation.
    const pamCriticalStart = site.strand === 'forward' ? site.position + 20 : site.position;
    const pamCriticalEnd = site.strand === 'forward' ? site.position + 23 : site.position + 3;

    const requiredStart = Math.min(mutationPosition, pamCriticalStart);
    const requiredEnd = Math.max(mutationPosition + 3, pamCriticalEnd);

    const requiredLen = requiredEnd - requiredStart;

    // If the required distance between mutation and PAM is larger than the oligo, we can't do it.
    if (requiredLen > oligoLength) continue;

    // We have "slack" to slide the window.
    // const slack = oligoLength - requiredLen; // Not strictly needed for logic, just concept

    // Possible start positions for the homology window:
    // The window must start at or before 'requiredStart'
    // The window must end at or after 'requiredEnd' -> start + oligoLength >= requiredEnd

    const minStart = Math.max(0, requiredEnd - oligoLength);
    const maxStart = Math.min(geneSequence.length - oligoLength, requiredStart);

    if (minStart > maxStart) continue; // Should be covered by requiredLen check, but safety first.

    // Determine optimal start to center the mutation
    // Ideal center is mutationPosition + 1.5
    // Window center is start + oligoLength / 2
    // We want start + oligoLength/2 ≈ mutationPosition + 1.5
    // => start ≈ mutationPosition + 1.5 - oligoLength/2
    const targetStart = Math.round(mutationPosition + 1.5 - (oligoLength / 2));

    // Clamp targetStart to our valid range [minStart, maxStart]
    let homologyStart = Math.max(minStart, Math.min(maxStart, targetStart));
    let homologyEnd = homologyStart + oligoLength;

    const originalHomologyRegion = geneSequence.substring(homologyStart, homologyEnd);
    const homologyList = originalHomologyRegion.split('');

    // 1. Apply Desired Mutation
    const codonStartInHomology = mutationPosition - homologyStart;
    if (codonStartInHomology >= 0 && codonStartInHomology < homologyList.length) {
      const originalCodon = homologyList.slice(codonStartInHomology, codonStartInHomology + 3).join('').toUpperCase();
      const newCodonOptions = CODON_TABLE[newAminoAcid.toUpperCase()];

      if (!newCodonOptions || newCodonOptions.length === 0) continue; 

      let newCodon = newCodonOptions[0];
      for (const opt of newCodonOptions) {
        if (opt !== originalCodon) {
          newCodon = opt;
          break;
        }
      }

      for (let i = 0; i < 3; i++) {
        homologyList[codonStartInHomology + i] = newCodon[i];
      }
    }

    let finalHomologyList = [...homologyList];
    let strategy: RepairResult['strategy'] | null = null;
    let silentMutationCount = 0;

    // 2. Check if Target Mutation disrupted PAM already
    const pamPosInHomology = pamStart - homologyStart;

    let pamAlreadyDisrupted = false;
    // Check critical indices for PAM disruption (GG for NGG)
    const criticalIndices = site.strand === 'forward'
        ? [pamPosInHomology + 21, pamPosInHomology + 22]
        : [pamPosInHomology, pamPosInHomology + 1];

    for(const idx of criticalIndices) {
        if (idx >= 0 && idx < homologyList.length) {
            if (homologyList[idx].toUpperCase() !== originalHomologyRegion[idx].toUpperCase()) {
                pamAlreadyDisrupted = true;
                break;
            }
        }
    }

    if (pamAlreadyDisrupted) {
        strategy = 'PAM_DISRUPTED_BY_TARGET';
        silentMutationCount = 0;
    } else {
        const pamAttempt = mutatePam(homologyList, site.strand, pamStart, homologyStart);
        if (pamAttempt.mutated && pamAttempt.strategy) {
            finalHomologyList = pamAttempt.sequence;
            strategy = pamAttempt.strategy;
            silentMutationCount = pamAttempt.mutationCount;
        } else {
            const seedAttempt = mutateSeed(homologyList, site.strand, pamStart, homologyStart);
            if (seedAttempt.mutated && seedAttempt.strategy) {
                finalHomologyList = seedAttempt.sequence;
                strategy = seedAttempt.strategy;
                silentMutationCount = seedAttempt.mutationCount;
            }
        }
    }

    if (!strategy) continue; 

    // 5. Format Case
    const finalCasedList: string[] = [];
    for (let i = 0; i < finalHomologyList.length; i++) {
      const finalChar = finalHomologyList[i];
      const originalChar = originalHomologyRegion[i];
      if (finalChar.toUpperCase() !== originalChar.toUpperCase()) {
        finalCasedList.push(finalChar.toLowerCase());
      } else {
        finalCasedList.push(finalChar.toUpperCase());
      }
    }
    const mutatedHomology = finalCasedList.join('');
    const revComp = reverseComplement(mutatedHomology);

    // 6. Generate Oligos
    const sgRNASeqWithPam = site.strand === 'reverse'
      ? reverseComplement(site.sequence)
      : site.sequence;

    // Calculate Score based on the canonical guide sequence
    const efficiencyScore = calculateEfficiencyScore(sgRNASeqWithPam);

    const guideSeq20nt = sgRNASeqWithPam.substring(0, 20).toUpperCase(); 

    const cloningOligoA = `gatc${guideSeq20nt}gttttagagctag`;
    const cloningOligoB = `ctagctctaaaac${reverseComplement(guideSeq20nt).toUpperCase()}`;

    // 7. Verification
    const contextFlank = 150;
    const alignStart = Math.max(0, mutationPosition - contextFlank);
    const alignEnd = Math.min(geneSequence.length, mutationPosition + 3 + contextFlank);
    const originalLargeDna = geneSequence.substring(alignStart, alignEnd);
    const repairedLargeList = originalLargeDna.split('');
    const tempStartInLarge = homologyStart - alignStart;

    for (let i = 0; i < mutatedHomology.length; i++) {
        if (tempStartInLarge + i >= 0 && tempStartInLarge + i < repairedLargeList.length) {
            repairedLargeList[tempStartInLarge + i] = mutatedHomology[i];
        }
    }
    const repairedLargeDna = repairedLargeList.join('');
    const frame = alignStart % 3;
    const originalLargeAA = translate(originalLargeDna.substring(frame));
    const repairedLargeAA = translate(repairedLargeDna.substring(frame));

    let aaDiffCount = 0;
    const len = Math.min(originalLargeAA.length, repairedLargeAA.length);
    for(let k=0; k<len; k++) {
        if (originalLargeAA[k] !== repairedLargeAA[k]) aaDiffCount++;
    }

    if (aaDiffCount !== 1) continue;

    results.push({
      site,
      cloningOligoA,
      cloningOligoB,
      repairTemplate: mutatedHomology,
      repairTemplateRevComp: revComp,
      originalRegion: originalHomologyRegion,
      homologyStart,
      mutationPosition,
      aaChangeStatus: 'success',
      aaChangesCount: aaDiffCount,
      dnaAlignment: {
          original: originalHomologyRegion.toUpperCase(),
          modified: mutatedHomology.toUpperCase(),
          matchString: generateSimpleAlignment(originalHomologyRegion.toUpperCase(), mutatedHomology.toUpperCase())
      },
      aaAlignment: {
          original: originalLargeAA,
          modified: repairedLargeAA,
          matchString: generateSimpleAlignment(originalLargeAA, repairedLargeAA)
      },
      strategy: strategy,
      silentMutationCount: silentMutationCount,
      score: efficiencyScore
    });
  }

  return results.slice(0, 5);
}
```

## App.tsx

-   Passed `oligoLength` to `findCas9Sites`.
-   Updated `renderAlphaMissenseInfo` to display a distinct "Not Found" card instead of hiding completely when `alphaMissense` is null. This confirms the tool attempted to fetch the data.

```tsx
import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ResultCard } from './components/ResultCard';
import { resolveGene, fetchAlphaMissense, AlphaMissenseResult } from './services/api';
import { findCas9Sites, generateRepairTemplates } from './services/crispr';
import { RepairResult } from './types';

export default function App() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<RepairResult[] | null>(null);
  const [currentGene, setCurrentGene] = useState<string>("");
  const [geneDescription, setGeneDescription] = useState<string | null>(null);
  const [alphaMissense, setAlphaMissense] = useState<AlphaMissenseResult | null>(null);
  const [isFetchingAM, setIsFetchingAM] = useState(false);
  const [residueForDisplay, setResidueForDisplay] = useState<string>("");
  const [mutationForDisplay, setMutationForDisplay] = useState<string>("");

  const handleGenerate = async (gene: string, residue: number, mutation: string, oligoLength: number) => {
    setLoading(true);
    setError(null);
    setResults(null);
    setGeneDescription(null);
    setAlphaMissense(null);
    setCurrentGene(gene);
    setResidueForDisplay(residue.toString());
    setMutationForDisplay(mutation);

    try {
      // 1. Fetch Gene Data (Symbol, ID, Sequence, Description)
      const geneInfo = await resolveGene(gene);
      setGeneDescription(geneInfo.description || null);

      // 2. Fetch AlphaMissense Data (Async, non-blocking for critical path)
      // Note: MyVariant dbNSFP is human-centric. We attempt to fetch if the user is designing for a conserved gene or human gene.
      setIsFetchingAM(true);
      fetchAlphaMissense(gene, residue, mutation).then(amData => {
          setAlphaMissense(amData);
          setIsFetchingAM(false);
      }).catch(e => {
          console.warn("Background AM fetch failed", e);
          setIsFetchingAM(false);
      });

      // 3. Find Sites
      // pass oligoLength to determine search window
      const sites = findCas9Sites(geneInfo.sequence, residue, oligoLength);

      if (sites.length === 0) {
        throw new Error("No nearby Cas9 target sites found within window.");
      }

      // 4. Generate Templates
      const generatedResults = generateRepairTemplates(
        geneInfo.sequence,
        sites,
        residue,
        mutation,
        oligoLength
      );

      if (generatedResults.length === 0) {
        throw new Error("No sgRNAs available where a silent PAM mutation could be successfully created within the selected oligo length.");
      }

      // 5. Sort results
      const getScoreCategory = (score: number): number => {
          if (score >= 70) return 3; // Green
          if (score >= 50) return 2; // Yellow
          return 1; // Red
      };

      const getStrategyPriority = (strategy: RepairResult['strategy']): number => {
          if (strategy === 'PAM_DISRUPTED_BY_TARGET' || strategy === 'PAM_SILENT') return 2;
          if (strategy === 'SEED_SILENT') return 1;
          return 0;
      };

      generatedResults.sort((a, b) => {
          const categoryA = getScoreCategory(a.score);
          const categoryB = getScoreCategory(b.score);
          if (categoryA !== categoryB) {
              return categoryB - categoryA; // Descending category (Green > Yellow > Red)
          }

          const strategyA = getStrategyPriority(a.strategy);
          const strategyB = getStrategyPriority(b.strategy);
          if (strategyA !== strategyB) {
              return strategyB - strategyA; // Descending priority (PAM > SEED)
          }

          // If category and strategy are the same, sort by raw score descending
          return b.score - a.score;
      });

      setResults(generatedResults);

    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
      setIsFetchingAM(false);
    } finally {
      setLoading(false);
    }
  };

  const renderAlphaMissenseInfo = () => {
      if (isFetchingAM) {
          return (
             <div className="bg-white border border-slate-200 rounded-xl p-4 mb-8 flex items-center gap-3 animate-pulse">
                <div className="h-10 w-10 bg-indigo-100 rounded-full flex items-center justify-center">
                    <svg className="w-5 h-5 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
                    </svg>
                </div>
                <div>
                   <div className="h-4 w-32 bg-slate-200 rounded mb-2"></div>
                   <div className="h-3 w-48 bg-slate-100 rounded"></div>
                </div>
             </div>
          );
      }

      if (!alphaMissense) {
          return (
             <div className="bg-slate-50 border border-slate-200 rounded-xl p-5 mb-8 flex items-center gap-4 opacity-75">
                 <div className="p-3 bg-slate-200 rounded-full text-slate-400">
                     <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                 </div>
                 <div>
                     <h4 className="font-bold text-slate-700 text-sm uppercase tracking-wider mb-1">AlphaMissense Prediction</h4>
                     <p className="text-sm text-slate-500">
                        No score found for <strong>{currentGene}</strong> p.{residueForDisplay}{mutationForDisplay} in dbNSFP/ClinVar.
                     </p>
                     <p className="text-xs text-slate-400 mt-1">
                        Note: This database primarily covers human genes.
                     </p>
                 </div>
            </div>
          );
      }

      const { score, pred_class } = alphaMissense;

      let classification = "Ambiguous";
      let colorClass = "bg-yellow-50 border-yellow-200 text-yellow-800";
      let icon = (
          <svg className="w-6 h-6 text-yellow-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
      );

      if (pred_class === 'pathogenic' || (!pred_class && score > 0.56)) {
          classification = "Likely Pathogenic";
          colorClass = "bg-red-50 border-red-200 text-red-800";
          icon = (
             <svg className="w-6 h-6 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
          );
      } else if (pred_class === 'benign' || (!pred_class && score < 0.34)) {
          classification = "Likely Benign";
          colorClass = "bg-green-50 border-green-200 text-green-800";
          icon = (
             <svg className="w-6 h-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
          );
      }

      return (
