To add the DIOPT Ortholog Finder feature, I will create a new service function to query the DIOPT API. This API provides the exact metrics requested: **Percent Identity**, **Percent Similarity**, and the **DIOPT Score** (confidence score).

**Plan:**
1.  **Update `types.ts`**: Define the `Ortholog` interface to store gene symbol, ID, score, identity, and similarity.
2.  **Update `services/api.ts`**: Add `fetchOrthologs` function. I will attempt to hit the DIOPT API first. If that fails (due to network/CORS), I will fall back to Ensembl to ensure robustness, though Ensembl primarily provides Identity.
3.  **Update `App.tsx`**: Add a new "Orthologs" card to the UI that displays the top human orthologs found for the yeast gene.

# Updated files:

## types.ts
Added `Ortholog` interface.

```typescript
export interface GeneInfo {
  id: string;
  symbol: string;
  sequence: string;
  description?: string;
}

export interface Cas9Site {
  position: number;
  sequence: string; // The full match including PAM
  strand: 'forward' | 'reverse';
}

export interface RepairResult {
  site: Cas9Site;
  cloningOligoA: string;
  cloningOligoB: string;
  repairTemplate: string; // The mutated homology arm
  repairTemplateRevComp: string; // For ordering
  originalRegion: string;
  homologyStart: number;
  mutationPosition: number; // Nucleotide index relative to start of gene
  aaChangeStatus: 'success' | 'warning';
  aaChangesCount: number;
  dnaAlignment: AlignmentData;
  aaAlignment: AlignmentData;
  strategy: 'PAM_DISRUPTED_BY_TARGET' | 'PAM_SILENT' | 'SEED_SILENT';
  silentMutationCount: number;
  score: number; // Efficiency Score (0-100)
}

export interface AlignmentData {
  original: string;
  modified: string;
  matchString: string; // String of '|' and ' '
}

export interface CodonTable {
  [key: string]: string[];
}

export interface Ortholog {
  symbol: string;
  geneId: string;
  score: number; // DIOPT Score (count of tools)
  bestScore: boolean;
  percentIdentity: number;
  percentSimilarity: number;
  source: 'DIOPT' | 'Ensembl';
}
```

## services/api.ts
Added `fetchOrthologs` which prioritizes DIOPT but has Ensembl fallback.

```typescript
import { GeneInfo, Ortholog } from '../types';

const ENSEMBL_BASE = "https://rest.ensembl.org";
const MYVARIANT_URL = "https://myvariant.info/v1/query";
const DIOPT_BASE = "https://www.flyrnai.org/tools/diopt/web/api/v1/orthologs";

export async function resolveGene(geneSymbol: string): Promise<GeneInfo> {
  // 1. Resolve Symbol to ID
  const xrefResponse = await fetch(
    `${ENSEMBL_BASE}/xrefs/symbol/saccharomyces_cerevisiae/${geneSymbol}?content-type=application/json`
  );
  if (!xrefResponse.ok) throw new Error("Gene symbol lookup failed");
  const xrefData = await xrefResponse.json();
  if (!xrefData.length) throw new Error(`Gene '${geneSymbol}' not found in Yeast database.`);

  const id = xrefData[0].id;

  // 2. Get Sequence
  const seqResponse = await fetch(
    `${ENSEMBL_BASE}/sequence/id/${id}?content-type=text/plain`
  );
  if (!seqResponse.ok) throw new Error("Sequence lookup failed");
  const sequence = await seqResponse.text();

  // 3. Get Gene Description
  let description = "No description available.";
  try {
      const lookupResponse = await fetch(
        `${ENSEMBL_BASE}/lookup/id/${id}?content-type=application/json`
      );
      if (lookupResponse.ok) {
          const lookupData = await lookupResponse.json();
          if (lookupData.description) {
              description = lookupData.description;
          }
      }
  } catch (e) {
      console.warn("Failed to fetch gene description", e);
  }

  return {
    id,
    symbol: geneSymbol,
    sequence: sequence.trim(),
    description
  };
}

export interface AlphaMissenseResult {
    score: number;
    pred_class: string;
}

export async function fetchAlphaMissense(gene: string, residue: number, mutation: string): Promise<AlphaMissenseResult | null> {
    try {
        const query = `q=dbnsfp.genename:${gene} AND dbnsfp.aapos:${residue}&fields=dbnsfp`;
        const response = await fetch(`${MYVARIANT_URL}?${query}`);

        if (!response.ok) return null;

        const data = await response.json();
        if (!data.hits || data.hits.length === 0) return null;

        for (const hit of data.hits) {
            if (!hit.dbnsfp) continue;

            const records = Array.isArray(hit.dbnsfp) ? hit.dbnsfp : [hit.dbnsfp];

            for (const record of records) {
                if (record.aaalt === mutation || record.aaalt === mutation.toUpperCase()) {
                    if (record.alphamissense) {
                        return {
                            score: parseFloat(record.alphamissense.score),
                            pred_class: record.alphamissense.pred_class
                        };
                    }
                }
            }
        }
        return null;
    } catch (error) {
        console.error("Error fetching AlphaMissense score:", error);
        return null;
    }
}

export async function fetchOrthologs(geneSymbol: string, ensemblId: string): Promise<Ortholog[]> {
    try {
        // Try DIOPT API First (Yeast ID: 4932, Human ID: 9606)
        // Note: DIOPT API might have CORS issues in some environments.
        const dioptUrl = `${DIOPT_BASE}/4932/${geneSymbol}/9606`;
        const response = await fetch(dioptUrl);

        if (response.ok) {
            const data = await response.json();
            if (data.results && data.results.length > 0 && data.results[0].orthologs) {
                return data.results[0].orthologs.map((o: any) => ({
                    symbol: o.symbol,
                    geneId: o.geneId,
                    score: o.score,
                    bestScore: o.bestScore === 'Yes' || o.bestScore === true,
                    percentIdentity: parseFloat(o.percentIdentity),
                    percentSimilarity: parseFloat(o.percentSimilarity),
                    source: 'DIOPT'
                })).sort((a: Ortholog, b: Ortholog) => b.score - a.score).slice(0, 5);
            }
        }
    } catch (e) {
        console.warn("DIOPT fetch failed, falling back to Ensembl", e);
    }

    // Fallback: Ensembl Homology
    try {
        const response = await fetch(
            `${ENSEMBL_BASE}/homology/id/${ensemblId}?target_species=human;type=orthologues;content-type=application/json`
        );

        if (response.ok) {
            const data = await response.json();
            if (data.data && data.data.length > 0) {
                const homologies = data.data[0].homologies || [];

                // We need to resolve symbols for Ensembl IDs efficiently
                // For now, we will just return the ID if symbol isn't easy to get in bulk without complex logic
                // But we can try to look at the 'protein_id' or 'id'

                const results: Ortholog[] = homologies.map((h: any) => ({
                    symbol: h.target.id, // Ensembl doesn't always give symbol in this endpoint easily
                    geneId: h.target.id,
                    score: 0, // Ensembl doesn't have a count score
                    bestScore: false,
                    percentIdentity: h.target.perc_id,
                    percentSimilarity: 0, // Not provided directly
                    source: 'Ensembl'
                }));

                return results.sort((a, b) => b.percentIdentity - a.percentIdentity).slice(0, 5);
            }
        }
    } catch (e) {
        console.error("Ensembl Homology fetch failed", e);
    }

    return [];
}
