}

export async function fetchOrthologs(geneSymbol: string, ensemblId: string, entrezId?: string): Promise<Ortholog[]> {
    const candidates: Map<string, Ortholog> = new Map();

    const addCandidate = (o: Ortholog) => {
        if (!candidates.has(o.geneId)) {
            candidates.set(o.geneId, o);
        } else {
            const existing = candidates.get(o.geneId)!;
            if (o.score > existing.score) {
                candidates.set(o.geneId, o);
            }
        }
    };

    // Helper to process response
    const processOrthologData = (data: any) => {
        if (!data) return;

        const resultsContainer = data.results || {};

        // DIOPT returns { results: { [InputID]: { [TargetID]: { ... } } } }
        // We need to find the object corresponding to our input ID.
        let orthologEntries = null;

        if (entrezId) {
            orthologEntries = resultsContainer[entrezId] || resultsContainer[Number(entrezId)];
        }

        // Fallback: use first key if we can't match exact Entrez ID or if it wasn't provided/matched
        if (!orthologEntries) {
            const keys = Object.keys(resultsContainer);
            if (keys.length > 0) {
                orthologEntries = resultsContainer[keys[0]];
            }
        }

        if (!orthologEntries) return;

        // Iterate over the target orthologs (values of the object)
        Object.values(orthologEntries).forEach((o: any) => {
             // Map fields robustly
             const symbol = o.symbol || o.gene_symbol;
             const geneId = o.geneId || o.geneid || o.entrez_id || o.species_specific_geneid;
             if (!symbol) return;

             const score = parseFloat(o.score) || 0;
             const bestScoreRaw = o.best_score || o.bestScore || o.best_score_rev;
             const bestScore = bestScoreRaw === 'Yes' || bestScoreRaw === true;

             const percentIdentity = parseFloat(o.percent_identity || o.percentIdentity) || 0;
             const percentSimilarity = parseFloat(o.percent_similarity || o.percentSimilarity) || 0;

             addCandidate({
                symbol: symbol,
                geneId: String(geneId),
                score: score,
                bestScore: bestScore,
                percentIdentity: percentIdentity,
                percentSimilarity: percentSimilarity,
                source: 'DIOPT'
            });
        });
    };

    const promises: Promise<any>[] = [];

    // 1. Primary: DIOPT with Entrez ID
    // Yeast (4932) -> Human (9606)
    if (entrezId) {
        const url = `https://www.flyrnai.org/tools/diopt/web/diopt_api/v9/get_orthologs_from_entrez/4932/${entrezId}/9606/none`;
        promises.push(
            fetchDioptData(url).then(data => {
                if (data) processOrthologData(data);
            })
        );
    }

    // 2. Fallback: Ensembl Homology
    promises.push(
        fetch(`${ENSEMBL_BASE}/homology/id/${ensemblId}?target_species=homo_sapiens;type=orthologues;content-type=application/json`)
            .then(r => r.ok ? r.json() : null)
            .then(data => {
                if (data?.data?.[0]?.homologies) {
                    data.data[0].homologies.forEach((h: any) => {
                        const geneId = h.target.id;
                        if (!candidates.has(geneId)) {
                            addCandidate({
                                symbol: h.target.id,
                                geneId: h.target.id,
                                score: 0, 
                                bestScore: false,
                                percentIdentity: h.target.perc_id,
                                percentSimilarity: h.target.perc_sim || 0,
                                source: 'Ensembl'
                            });
                        }
                    });
                }
            })
            .catch(e => { console.warn("Ensembl Homology fetch failed", e); })
    );

    await Promise.all(promises);

    const finalResults = Array.from(candidates.values());

    return finalResults.sort((a, b) => {
        if (a.score !== b.score) return b.score - a.score;
        if (a.bestScore !== b.bestScore) return a.bestScore ? -1 : 1;
        return b.percentIdentity - a.percentIdentity;
    }).slice(0, 15);
}

