    promises.push(
        fetch(`${ENSEMBL_BASE}/homology/id/${ensemblId}?target_species=homo_sapiens;type=orthologues;content-type=application/json`)
            .then(r => r.ok ? r.json() : null)
            .then(data => {
                if (data?.data?.[0]?.homologies) {
                    data.data[0].homologies.forEach((h: any) => {
                        const targetSymbol = h.target.id; // Ensembl target ID usually, sometimes they provide display_id
                        // We need the symbol for robust merging. Ensembl might return HGNC symbol in 'display_id' or 'id'
                        // We will blindly trust the ID they give us, but map it.
                        // Ideally we'd look up the symbol, but let's assume 'target.id' or 'target.protein_id' isn't what we want for display.
                        // However, Ensembl Homology object structure: h.target.id is ENSG... 
                        // We try to grab the symbol if it exists in 'species' specific fields, otherwise we rely on DIOPT to have set the symbol first.
                        // If DIOPT didn't find it, we add it with ID.

                        addOrUpdateCandidate({
                            symbol: h.target.id, // Fallback if no symbol known yet. Merging might miss if DIOPT has "WNT1" and this is "ENSG000..."
                            geneId: h.target.id,
                            score: 0, 
                            bestScore: false,
                            percentIdentity: h.target.perc_id,
                            percentSimilarity: h.target.perc_sim || 0,
                            source: 'Ensembl'
                        });

                        // Try to merge into existing keys if possible (Double check common symbols?)
                        // Since we don't have the symbol for the Ensembl ID easily without another fetch, 
                        // we can iterate the existing candidates and see if any geneId matches this target.id (unlikely, Entrez vs Ensembl)
                        // Or we just rely on DIOPT being the primary source of truth for Symbol.
                        // Refinement: Ensembl often doesn't give the gene symbol in the homology response directly.
                    });
                }
            })
            .catch(e => { console.warn("Ensembl Homology fetch failed", e); })
    );

    await Promise.all(promises);

    const finalResults = Array.from(candidates.values());

    return finalResults.sort((a, b) => {
        // Sort Priority:
        // 1. Best Score (Boolean)
        // 2. DIOPT Score (Numeric)
        // 3. Percent Identity (Numeric)
        if (a.bestScore !== b.bestScore) return a.bestScore ? -1 : 1;
        if (a.score !== b.score) return b.score - a.score;
        return b.percentIdentity - a.percentIdentity;
    }).slice(0, 15);
}

import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ResultCard } from './components/ResultCard';
import { resolveGene, fetchVepScore, fetchOrthologs } from './services/api';
import { findCas9Sites, generateRepairTemplates } from './services/crispr';
import { RepairResult, Ortholog, VariantEffectResult } from './types';

export default function App() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<RepairResult[] | null>(null);

  const [currentGene, setCurrentGene] = useState<string>("");
  const [currentEntrezId, setCurrentEntrezId] = useState<string | null>(null);
  const [geneDescription, setGeneDescription] = useState<string | null>(null);

  const [variantEffect, setVariantEffect] = useState<VariantEffectResult | null>(null);
  const [isFetchingEffect, setIsFetchingEffect] = useState(false);

  const [orthologs, setOrthologs] = useState<Ortholog[]>([]);
  const [isFetchingOrthologs, setIsFetchingOrthologs] = useState(false);

  const [residueForDisplay, setResidueForDisplay] = useState<string>("");
  const [mutationForDisplay, setMutationForDisplay] = useState<string>("");

  const handleGenerate = async (geneInput: string, residue: number, mutation: string, oligoLength: number) => {
    setLoading(true);
    setError(null);
    setResults(null);
    setGeneDescription(null);
    setVariantEffect(null);
    setOrthologs([]);
    setCurrentEntrezId(null);

    // Initially set input gene, will update with canonical later
    setCurrentGene(geneInput);
    setResidueForDisplay(residue.toString());
    setMutationForDisplay(mutation);

    try {
      // 1. Fetch Gene Data (Symbol, ID, Sequence, Description, Transcript, EntrezID)
      const geneInfo = await resolveGene(geneInput);

      // Update with canonical symbol (e.g. user types "pho13" -> "PHO13")
      setCurrentGene(geneInfo.symbol);
      setCurrentEntrezId(geneInfo.entrezId || null);
      setGeneDescription(geneInfo.description || null);

      // 2. Fetch Orthologs (Human)
      // Parallel fetch using Symbol, EnsemblID AND EntrezID
      setIsFetchingOrthologs(true);
      fetchOrthologs(geneInfo.symbol, geneInfo.id, geneInfo.entrezId).then(data => {
          setOrthologs(data);
          setIsFetchingOrthologs(false);
      }).catch(e => {
          console.warn("Ortholog fetch failed", e);
          setIsFetchingOrthologs(false);
      });

      // 3. Fetch Variant Effect (SIFT/VEP)
      if (geneInfo.transcriptId) {
          setIsFetchingEffect(true);
          fetchVepScore(geneInfo.transcriptId, residue, mutation, geneInfo.sequence).then(effect => {
              setVariantEffect(effect);
              setIsFetchingEffect(false);
          }).catch(e => {
              console.warn("VEP fetch failed", e);
              setIsFetchingEffect(false);
          });
      }

      // 4. Find Sites
      const sites = findCas9Sites(geneInfo.sequence, residue);

      if (sites.length === 0) {
        throw new Error("No nearby Cas9 target sites found within window.");
      }

      // 5. Generate Templates
      const generatedResults = generateRepairTemplates(
        geneInfo.sequence,
        sites,
        residue,
        mutation,
        oligoLength
      );

      if (generatedResults.length === 0) {
        throw new Error("No sgRNAs available where a silent PAM mutation could be successfully created within the selected oligo length.");
      }

      // 6. Sort results
      const getScoreCategory = (score: number): number => {
          if (score >= 70) return 3; // Green
          if (score >= 50) return 2; // Yellow
          return 1; // Red
      };

      const getStrategyPriority = (strategy: RepairResult['strategy']): number => {
          if (strategy === 'PAM_DISRUPTED_BY_TARGET' || strategy === 'PAM_SILENT') return 2;
          if (strategy === 'SEED_SILENT') return 1;
          return 0;
      };

      generatedResults.sort((a, b) => {
          const categoryA = getScoreCategory(a.score);
          const categoryB = getScoreCategory(b.score);
          if (categoryA !== categoryB) {
              return categoryB - categoryA; // Descending category (Green > Yellow > Red)
          }

          const strategyA = getStrategyPriority(a.strategy);
          const strategyB = getStrategyPriority(b.strategy);
          if (strategyA !== strategyB) {
              return strategyB - strategyA; // Descending priority (PAM > SEED)
          }

          return b.score - a.score;
      });

      setResults(generatedResults);

    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
      setIsFetchingEffect(false);
      setIsFetchingOrthologs(false);
    } finally {
      setLoading(false);
    }
  };

  const renderOrthologs = () => {
      // Always show if fetching
      if (isFetchingOrthologs) {
          return (
             <div className="bg-white border border-slate-200 rounded-xl p-4 mb-4 flex items-center gap-3 animate-pulse">
                <div className="h-8 w-8 bg-sky-100 rounded-full"></div>
                <div className="flex-1 space-y-2">
                   <div className="h-3 w-32 bg-slate-200 rounded"></div>
                   <div className="h-2 w-48 bg-slate-100 rounded"></div>
                </div>
             </div>
          );
      }

      // Don't render if we haven't searched yet
      if (!results && !loading) return null;

      const hasOrthologs = orthologs.length > 0;

      // Construct DIOPT link. Prefer Entrez ID + Species ID 4932 (Yeast).
      const dioptLink = currentEntrezId 
        ? `https://www.flyrnai.org/cgi-bin/DRSC_orthologs.pl?sc=1&species=4932&input=${currentEntrezId}`
        : `https://www.flyrnai.org/cgi-bin/DRSC_orthologs.pl?sc=1&species=Yeast&input=${currentGene}`;

      return (
          <div className="bg-sky-50 border border-sky-100 rounded-xl p-5 mb-4 shadow-sm">
              <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                      <div className="p-1.5 bg-sky-100 rounded-lg text-sky-600">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                      </div>
                      <div>
                          <h3 className="font-bold text-sky-900 text-sm uppercase tracking-wider">Human Orthologs</h3>
                          <p className="text-xs text-slate-500">Sorted by score (DIOPT)</p>
                      </div>
                  </div>
                  <a href={dioptLink} target="_blank" rel="noopener noreferrer" className="text-xs text-sky-600 font-medium hover:underline flex items-center gap-1">
                      View in DIOPT
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                  </a>
              </div>

              <div className="overflow-x-auto max-h-64 overflow-y-auto border rounded-lg border-sky-100">
                {hasOrthologs ? (
                  <table className="w-full text-sm text-left bg-white">
                      <thead className="text-xs text-sky-800 uppercase bg-sky-50 sticky top-0 shadow-sm z-10">
                          <tr>
                              <th className="px-3 py-2">Symbol</th>
                              <th className="px-3 py-2">Identity</th>
                              <th className="px-3 py-2">Similarity</th>
                              <th className="px-3 py-2">DIOPT Score</th>
                          </tr>
                      </thead>
                      <tbody>
                          {orthologs.map((orth, idx) => (
                              <tr key={idx} className="border-b border-sky-50 last:border-0 hover:bg-sky-50 transition-colors">
                                  <td className="px-3 py-2 font-bold text-slate-700">
                                      {orth.symbol}
                                      {orth.bestScore && <span className="ml-2 text-[10px] bg-sky-200 text-sky-800 px-1.5 py-0.5 rounded-full" title="Best Score">Best</span>}
                                  </td>
                                  <td className="px-3 py-2 text-slate-600 font-mono">
                                      {orth.percentIdentity ? `${orth.percentIdentity.toFixed(0)}%` : '-'}
                                  </td>
                                  <td className="px-3 py-2 text-slate-600 font-mono">
                                      {orth.percentSimilarity ? `${orth.percentSimilarity.toFixed(0)}%` : '-'}
                                  </td>
                                  <td className="px-3 py-2">
                                      {orth.source === 'DIOPT' ? (
                                          <div className="flex items-center gap-2">
                                             <div className="h-1.5 w-12 bg-slate-200 rounded-full overflow-hidden">
                                                 <div className="h-full bg-sky-500" style={{ width: `${Math.min(100, (orth.score / 15) * 100)}%` }}></div>
                                             </div>
                                             <span className="text-xs text-slate-700 font-medium">{orth.score}</span>
                                          </div>
                                      ) : (
                                          <span className="text-xs text-slate-400 italic">Ensembl</span>
                                      )}
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
                  ) : (
                      <div className="text-center py-4 text-sm text-slate-500 italic">
                          No orthologs found directly.
                      </div>
                  )}
              </div>
          </div>
      );
  };

  const renderVariantEffectInfo = () => {
      if (isFetchingEffect) {
          return (
             <div className="bg-white border border-slate-200 rounded-xl p-4 mb-8 flex items-center gap-3 animate-pulse">
                <div className="h-10 w-10 bg-indigo-100 rounded-full flex items-center justify-center">
                    <svg className="w-5 h-5 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
                    </svg>
                </div>
                <div>
                   <div className="h-4 w-32 bg-slate-200 rounded mb-2"></div>
                   <div className="h-3 w-48 bg-slate-100 rounded"></div>
                </div>
             </div>
          );
      }

      if (!variantEffect) {
          return (
             <div className="bg-slate-50 border border-slate-200 rounded-xl p-5 mb-8 flex items-center gap-4 opacity-75">
                 <div className="p-3 bg-slate-200 rounded-full text-slate-400">
                     <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                 </div>
                 <div>
                     <h4 className="font-bold text-slate-700 text-sm uppercase tracking-wider mb-1">Effect Prediction</h4>
                     <p className="text-sm text-slate-500">
                        No pre-computed SIFT or AlphaMissense score found for <strong>{currentGene}</strong> p.{residueForDisplay}{mutationForDisplay}.
                     </p>
                     <p className="text-xs text-slate-400 mt-1">
                        Try checking Ensembl VEP directly.
                     </p>
                 </div>
            </div>
          );
      }

      const { score, prediction, amClass, amPathogenicity } = variantEffect;

      const isDeleterious = (score !== undefined && score <= 0.05) || 
                            (prediction && prediction.includes('deleterious')) ||
                            (amClass && (amClass === 'likely_pathogenic' || amClass === 'pathogenic'));

      let colorClass = isDeleterious 
        ? "bg-red-50 border-red-200 text-red-800"
        : "bg-green-50 border-green-200 text-green-800";

      let icon = isDeleterious ? (
         <svg className="w-6 h-6 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
      ) : (
         <svg className="w-6 h-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
      );

      return (
          <div className={`rounded-xl p-5 mb-8 border flex flex-col md:flex-row items-center justify-between shadow-sm gap-4 ${colorClass}`}>
             <div className="flex items-center gap-4 w-full md:w-auto">
                 <div className="p-3 bg-white bg-opacity-60 rounded-full shadow-sm shrink-0">
                     {icon}
                 </div>
                 <div>
                     <h4 className="font-bold text-xs uppercase tracking-wider opacity-70 mb-1">Variant Effect</h4>
                     <div className="flex flex-col gap-1">
                        <div className="flex items-baseline gap-3">
                           <span className="text-xs font-semibold opacity-60">SIFT:</span>
                           {score !== undefined ? (
                               <span className="text-xl font-bold tracking-tight">{score.toFixed(2)}</span>
                           ) : (
                               <span className="text-sm italic opacity-50">N/A</span>
                           )}
                           <span className="font-semibold text-sm border-l border-current pl-3 opacity-90 capitalize">{prediction.replace(/_/g, ' ')}</span>
                        </div>

                        {/* AlphaMissense Line */}
                        {(amClass || amPathogenicity !== undefined) && (
                            <div className="flex items-baseline gap-3 border-t border-current border-opacity-20 pt-1 mt-1">
                               <span className="text-xs font-semibold opacity-60">AlphaMissense:</span>
                               {amPathogenicity !== undefined ? (
                                   <span className="text-xl font-bold tracking-tight">{amPathogenicity.toFixed(2)}</span>
                               ) : null}
                               {amClass && (
                                   <span className="font-semibold text-sm border-l border-current pl-3 opacity-90 capitalize">{amClass.replace(/_/g, ' ')}</span>
                               )}
                            </div>
                        )}
                     </div>
                 </div>
             </div>
             <div className="text-right w-full md:w-auto shrink-0">
                <a href="https://www.ensembl.org/info/docs/tools/vep/index.html" target="_blank" rel="noopener noreferrer" className="text-xs font-medium underline opacity-60 hover:opacity-100 block mb-1">
                   Source: Ensembl VEP
                </a>
                <span className="text-[10px] uppercase opacity-50 font-bold tracking-wider">Yeast Score</span>
             </div>
          </div>
      );
  };

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900 pb-20">
      {/* Header */}
      <header className="bg-indigo-700 text-white py-8 shadow-lg">
        <div className="container mx-auto px-4 max-w-5xl">
          <h1 className="text-3xl font-bold tracking-tight mb-2">CODY - CRISPR Oligo Designer for Yeast</h1>
          <p className="text-indigo-200">Automated repair template and cloning oligo design for point mutations in <span className="italic">S. cerevisiae</span>.</p>
        </div>
      </header>

      <main className="container mx-auto px-4 max-w-5xl -mt-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left Column: Input */}
          <div className="lg:col-span-1 space-y-6">
            <InputForm isLoading={loading} onSubmit={handleGenerate} />

            {/* Context Info Box */}
            <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
               <h3 className="text-sm font-bold text-slate-800 uppercase tracking-wider mb-2">Instructions</h3>
               <ul className="text-sm text-slate-600 space-y-2 list-disc pl-4">
                 <li>Enter the standard Yeast gene name (e.g., PHO13).</li>
                 <li>Enter the amino acid residue number to mutate.</li>
                 <li>Enter the single-letter code for the <strong>new</strong> amino acid.</li>
                 <li>Adjust the oligo length slider to match your synthesis constraints (e.g. 90-mer).</li>
                 <li>The tool finds Cas9 sites and designs silent PAM mutations.</li>
                 <li className="pt-2 border-t border-slate-100 mt-2">
                    <span className="font-semibold">Legend:</span>
                    <ul className="list-none pl-0 mt-1 space-y-1">
                        <li><span className="text-red-600 font-bold">Red</span> text indicates mutations.</li>
                        <li><span className="text-purple-600 font-bold">Purple</span> text indicates PAM sites.</li>
                    </ul>
                 </li>
               </ul>
            </div>
          </div>

          {/* Right Column: Results */}
          <div className="lg:col-span-2">
            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl mb-6 shadow-sm">
                <strong>Error:</strong> {error}
              </div>
            )}

            {loading && !results && (
                <div className="flex flex-col items-center justify-center py-20 space-y-4 text-slate-400">
                    <div className="w-12 h-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                    <p>Analyzing gene sequence and calculating alignments...</p>
                </div>
            )}

            {!loading && !results && !error && (
              <div className="flex flex-col items-center justify-center py-20 bg-white rounded-xl border border-slate-200 border-dashed text-slate-400">
                 <svg className="w-16 h-16 mb-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path>
                 </svg>
                 <p className="text-lg font-medium">Ready to design</p>
                 <p className="text-sm">Enter parameters to begin.</p>
              </div>
            )}

            {results && (
              <div className="animate-fade-in">
                 {/* Gene Context Card */}
                 <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 mb-4">
                    <div className="flex items-start gap-4">
                        <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600">
                           <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-indigo-900 mb-1">Gene: {currentGene}</h3>
                            <p className="text-indigo-800 text-sm leading-relaxed">
                                {geneDescription || "No description available."}
                            </p>
                        </div>
                    </div>
                 </div>

                 {/* Orthologs Card */}
                 {renderOrthologs()}

                 {/* Variant Effect (SIFT) Score Card - Replaces AlphaMissense */}
                 {renderVariantEffectInfo()}

                <div className="flex items-center justify-between mb-6">
                   <h2 className="text-2xl font-bold text-slate-800">Design Results</h2>
                   <span className="bg-slate-200 text-slate-700 px-3 py-1 rounded-full text-xs font-bold">
                     {results.length} Options Found
                   </span>
                </div>

                {results.map((result, idx) => (
                  <ResultCard key={idx} result={result} index={idx} />
                ))}
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}

export interface GeneInfo {
  id: string;
  transcriptId?: string;
  entrezId?: string;
  symbol: string;
  sequence: string;
  description?: string;
}

export interface Cas9Site {
  position: number;
  sequence: string;
  strand: 'forward' | 'reverse';
}

export interface RepairResult {
  site: Cas9Site;
  cloningOligoA: string;
  cloningOligoB: string;
  repairTemplate: string;
  repairTemplateRevComp: string;
  originalRegion: string;
  homologyStart: number;
  mutationPosition: number;
  aaChangeStatus: 'success' | 'warning';
  aaChangesCount: number;
  dnaAlignment: AlignmentData;
  aaAlignment: AlignmentData;
  strategy: 'PAM_DISRUPTED_BY_TARGET' | 'PAM_SILENT' | 'SEED_SILENT';
  silentMutationCount: number;
  score: number;
}

export interface AlignmentData {
  original: string;
  modified: string;
  matchString: string;
}

export interface CodonTable {
  [key: string]: string[];
}

export interface Ortholog {
  symbol: string;
  geneId: string; // Entrez ID or Ensembl ID
  ensemblId?: string; // Specific field for ENSG ID to help merging
  score: number; // DIOPT Score
  bestScore: boolean;
  percentIdentity: number;
  percentSimilarity: number;
  source: 'DIOPT' | 'Ensembl' | 'Merged';
  // Alignment data for mapping residues
  alignment?: {
      sourceSeq: string; // Yeast Aligned Seq (with gaps)
      targetSeq: string; // Human Aligned Seq (with gaps)
  };
}

export interface HumanAnalysisResult {
    orthologSymbol: string;
    humanResidue: number;
    humanRefAA: string;
    isConserved: boolean;
    amClass?: string;
    amPathogenicity?: number;
    siftScore?: number;
    siftPrediction?: string;
    polyphenScore?: number;
    polyphenPrediction?: string;
}

export interface VariantEffectResult {
    score?: number; // Yeast SIFT Score
    prediction: string; // 'tolerated' | 'deleterious'
    source: string;
    // Proxied Human Data
    humanAnalysis?: HumanAnalysisResult;
}

import { GeneInfo, Ortholog, VariantEffectResult, HumanAnalysisResult } from '../types';
import { toThreeLetterAA, codonToAA } from './utils';

const ENSEMBL_BASE = "https://rest.ensembl.org";

export async function resolveGene(geneSymbol: string): Promise<GeneInfo> {
  const xrefResponse = await fetch(
    `${ENSEMBL_BASE}/xrefs/symbol/saccharomyces_cerevisiae/${geneSymbol}?content-type=application/json`
  );
  if (!xrefResponse.ok) throw new Error("Gene symbol lookup failed");
  const xrefData = await xrefResponse.json();
  if (!xrefData.length) throw new Error(`Gene '${geneSymbol}' not found in Yeast database.`);

  const id = xrefData[0].id;
  const canonicalSymbol = xrefData[0].display_id || geneSymbol;

  const seqResponse = await fetch(
    `${ENSEMBL_BASE}/sequence/id/${id}?type=cds;content-type=text/plain`
  );
  if (!seqResponse.ok) throw new Error("Sequence lookup failed");
  const sequence = await seqResponse.text();

  let description = "No description available.";
  let transcriptId = id;
  let entrezId: string | undefined;

  try {
      const [lookupResponse, entrezResponse] = await Promise.all([
          fetch(`${ENSEMBL_BASE}/lookup/id/${id}?expand=1&content-type=application/json`),
          fetch(`${ENSEMBL_BASE}/xrefs/id/${id}?external_db=EntrezGene;content-type=application/json`)
      ]);

      if (lookupResponse.ok) {
          const lookupData = await lookupResponse.json();
          if (lookupData.description) description = lookupData.description;
          if (lookupData.Transcript && lookupData.Transcript.length > 0) {
              transcriptId = lookupData.Transcript[0].id;
          }
      }

      if (entrezResponse.ok) {
          const entrezData = await entrezResponse.json();
          if (entrezData && entrezData.length > 0) {
              entrezId = entrezData[0].primary_id;
          }
      }

  } catch (e) {
      console.warn("Failed to fetch gene details or Entrez ID", e);
  }

  return { id, transcriptId, entrezId, symbol: canonicalSymbol, sequence: sequence.trim(), description };
}

export async function fetchVepScore(
    transcriptId: string, 
    residue: number, 
    mutation: string, 
    originalSequence: string
): Promise<VariantEffectResult | null> {
    try {
        const codonIndex = (residue - 1) * 3;
        if (codonIndex >= originalSequence.length) return null;

        const originalCodon = originalSequence.substring(codonIndex, codonIndex + 3);
        const originalAA = codonToAA(originalCodon);

        if (!originalAA) return null;

        if (originalAA === mutation) {
            return { prediction: "synonymous_variant", source: "Calculated (Identity)" };
        }

        const threeLetterRef = toThreeLetterAA(originalAA);
        const threeLetterAlt = toThreeLetterAA(mutation);
        const hgvs = `${transcriptId}:p.${threeLetterRef}${residue}${threeLetterAlt}`;

        // Yeast SIFT call
        const response = await fetch(
            `${ENSEMBL_BASE}/vep/saccharomyces_cerevisiae/hgvs/${hgvs}?content-type=application/json`
        );

        if (!response.ok) return null;

        const data = await response.json();
        if (!data || data.length === 0) return null;

        const consequences = data[0].transcript_consequences;
        if (consequences) {
            let match = consequences.find((c: any) => c.transcript_id === transcriptId && c.sift_score !== undefined);
            if (!match) match = consequences.find((c: any) => c.sift_score !== undefined);
            if (!match) match = consequences.find((c: any) => c.transcript_id === transcriptId);

            if (match) {
                 const prediction = match.sift_prediction 
                    || match.consequence_terms?.[0] 
                    || (match.sift_score !== undefined ? (match.sift_score <= 0.05 ? 'deleterious' : 'tolerated') : 'unknown effect');

                 return {
                    score: match.sift_score,
                    prediction: prediction,
                    source: 'Ensembl VEP (Yeast)'
                };
            }
        }
        return null;
    } catch (e) {
        console.error("VEP Fetch Error:", e);
        return null;
    }
}

// --- ORTHOLOG & ALPHAMISSENSE PROXY LOGIC ---

// 1. Fetch Human VEP (AlphaMissense)
export async function fetchHumanVariantEffect(
    humanGeneId: string,
    humanResidue: number,
    humanRefAA: string,
    mutationAA: string
): Promise<HumanAnalysisResult | null> {
    try {
        // 1. Get Canonical Transcript for Human Gene
        const lookupRes = await fetch(`${ENSEMBL_BASE}/lookup/id/${humanGeneId}?expand=1&content-type=application/json`);
        if (!lookupRes.ok) return null;
        const lookupData = await lookupRes.json();

        const transcript = lookupData.Transcript?.find((t: any) => t.is_canonical === 1) || lookupData.Transcript?.[0];
        if (!transcript) return null;

        // 2. Construct HGVS
        const threeRef = toThreeLetterAA(humanRefAA);
        const threeAlt = toThreeLetterAA(mutationAA);
        const hgvs = `${transcript.id}:p.${threeRef}${humanResidue}${threeAlt}`;

        // 3. Call Human VEP with AlphaMissense enabled
        const vepRes = await fetch(
            `${ENSEMBL_BASE}/vep/human/hgvs/${hgvs}?content-type=application/json&AlphaMissense=1&Polyphen=1`
        );
        if (!vepRes.ok) return null;
        const vepData = await vepRes.json();

        if (!vepData || vepData.length === 0) return null;

        const match = vepData[0].transcript_consequences?.find((c: any) => c.transcript_id === transcript.id) 
                   || vepData[0].transcript_consequences?.[0];

        if (!match) return null;

        return {
            orthologSymbol: lookupData.display_name || lookupData.id,
            humanResidue: humanResidue,
            humanRefAA: humanRefAA,
            isConserved: true, // Function is only called if conserved
            amClass: match.am_class || match.alphamissense_class,
            amPathogenicity: match.am_pathogenicity !== undefined ? parseFloat(match.am_pathogenicity) : (match.alphamissense_score ? parseFloat(match.alphamissense_score) : undefined),
            siftScore: match.sift_score,
            siftPrediction: match.sift_prediction,
            polyphenScore: match.polyphen_score,
            polyphenPrediction: match.polyphen_prediction
        };

    } catch (e) {
        console.warn("Error fetching human variant effect", e);
        return null;
    }
}

// 2. Map Yeast Residue to Human Residue using Alignment
export function mapResidueToOrtholog(
    yeastResidueIndex: number, // 1-based
    alignment: { sourceSeq: string, targetSeq: string }
): { humanResidueIndex: number, humanAA: string } | null {
    const { sourceSeq, targetSeq } = alignment;

    // Iterate through source (Yeast) sequence to find the column corresponding to the residue
    let currentYeastIndex = 0;
    let alignmentColumn = -1;

    for (let i = 0; i < sourceSeq.length; i++) {
        if (sourceSeq[i] !== '-') {
            currentYeastIndex++;
        }
        if (currentYeastIndex === yeastResidueIndex) {
            alignmentColumn = i;
            break;
        }
    }

    if (alignmentColumn === -1) return null;

    // Check target (Human) sequence at that column
    const humanAA = targetSeq[alignmentColumn];
    if (humanAA === '-' || humanAA === undefined) return null; // Gap in human, cannot map

    // Count human residues up to that column to get index
    let currentHumanIndex = 0;
    for (let i = 0; i <= alignmentColumn; i++) {
        if (targetSeq[i] !== '-') {
            currentHumanIndex++;
        }
    }

    return {
        humanResidueIndex: currentHumanIndex,
        humanAA: humanAA
    };
}

async function fetchDioptData(url: string): Promise<any | null> {
    // Strategy: CorsProxy.io
    try {
        const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(url)}`;
        const response = await fetch(proxyUrl);
        if (response.ok) return await response.json();
    } catch (e) {
        // console.warn("CorsProxy failed", e);
    }
    // Fallback: AllOrigins
    try {
        const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
        const response = await fetch(proxyUrl);
        if (response.ok) {
            const wrapper = await response.json();
            if (wrapper.contents) return JSON.parse(wrapper.contents);
        }
    } catch (e) {
        console.warn("AllOrigins failed", e);
    }
    return null;
}

export async function fetchOrthologs(geneSymbol: string, ensemblId: string, entrezId?: string): Promise<Ortholog[]> {
    const candidates: Map<string, Ortholog> = new Map();
    // Index keys: We use both the EnsemblID (if available) and the Symbol to robustly merge.
    // DIOPT gives Ensembl IDs in 'species_specific_geneid' for Human (9606) usually? 
    // Wait, 'species_specific_geneid' for Human in DIOPT is usually HGNC or Entrez. 
    // Let's rely on mapping.

    const addOrUpdate = (o: Ortholog, key: string) => {
        if (!candidates.has(key)) {
            candidates.set(key, o);
        } else {
            const existing = candidates.get(key)!;
            // Merge Stats
            candidates.set(key, {
                ...existing,
                ensemblId: o.ensemblId || existing.ensemblId, // Keep Ensembl ID if found
                score: Math.max(existing.score, o.score),
                bestScore: existing.bestScore || o.bestScore,
                percentIdentity: o.percentIdentity > 0 ? o.percentIdentity : existing.percentIdentity,
                percentSimilarity: o.percentSimilarity > 0 ? o.percentSimilarity : existing.percentSimilarity,
                source: 'Merged',
                alignment: o.alignment || existing.alignment
            });
        }
    };

    const promises: Promise<any>[] = [];

    // 1. DIOPT
    if (entrezId) {
        const url = `https://www.flyrnai.org/tools/diopt/web/diopt_api/v9/get_orthologs_from_entrez/4932/${entrezId}/9606/none`;
        promises.push(
            fetchDioptData(url).then(data => {
                if (!data || !data.results) return;
                const resultsContainer = data.results;
                let entries = resultsContainer[entrezId] || resultsContainer[Number(entrezId)];
                if (!entries && Object.keys(resultsContainer).length > 0) entries = resultsContainer[Object.keys(resultsContainer)[0]];

                if (entries) {
                    Object.values(entries).forEach((o: any) => {
                        const symbol = o.symbol || o.gene_symbol;
                        // DIOPT 'species_specific_geneid' for Human is often Entrez ID.
                        // However, sometimes we can find Ensembl ID in other fields? 
                        // We will mainly index by SYMBOL here.
                        if (!symbol) return;

                        addOrUpdate({
                            symbol: symbol,
                            geneId: String(o.geneid || o.entrez_id),
                            score: parseFloat(o.score) || 0,
                            bestScore: o.best_score === "Yes" || o.best_score === true,
                            percentIdentity: parseFloat(o.percent_identity) || 0,
                            percentSimilarity: parseFloat(o.percent_similarity) || 0,
                            source: 'DIOPT'
                        }, symbol.toUpperCase());
                    });
                }
            })
        );
    }

    // 2. Ensembl Homology (With Sequence for alignment)
    promises.push(
        fetch(`${ENSEMBL_BASE}/homology/id/${ensemblId}?target_species=homo_sapiens;type=orthologues;content-type=application/json;sequence=1`)
            .then(r => r.ok ? r.json() : null)
            .then(data => {
                if (data?.data?.[0]?.homologies) {
                    data.data[0].homologies.forEach((h: any) => {
                        const targetId = h.target.id; // Ensembl ID (ENSG...)
                        // Try to find Symbol from display_id or id
                        // display_id often has the symbol for human genes in Ensembl
                        let symbol = h.target.display_id || targetId;

                        // NOTE: Ensembl ID is crucial for the AlphaMissense fetch later

                        const ortholog: Ortholog = {
                            symbol: symbol,
                            geneId: targetId,
                            ensemblId: targetId,
                            score: 0,
                            bestScore: false,
                            percentIdentity: h.target.perc_id,
                            percentSimilarity: h.target.perc_pos || 0, // perc_pos is usually similarity
                            source: 'Ensembl',
                            alignment: {
                                sourceSeq: h.source.align_seq,
                                targetSeq: h.target.align_seq
                            }
                        };

                        // Merge logic:
                        // 1. Try to merge by Symbol (uppercase)
                        // 2. If symbol is ENSG id (no display_id), we might fail to merge with DIOPT if DIOPT has "WNT1".
                        //    But often display_id is correct.
                        addOrUpdate(ortholog, symbol.toUpperCase());
                    });
                }
            })
            .catch(e => console.warn("Ensembl Homology failed", e))
    );

    await Promise.all(promises);

    const finalResults = Array.from(candidates.values());

    return finalResults.sort((a, b) => {
        if (a.bestScore !== b.bestScore) return a.bestScore ? -1 : 1;
        if (a.score !== b.score) return b.score - a.score;
        return b.percentIdentity - a.percentIdentity;
    }).slice(0, 15);
}

import React, { useState } from 'react';
import { InputForm } from './components/InputForm';
import { ResultCard } from './components/ResultCard';
import { resolveGene, fetchVepScore, fetchOrthologs, mapResidueToOrtholog, fetchHumanVariantEffect } from './services/api';
import { findCas9Sites, generateRepairTemplates } from './services/crispr';
import { RepairResult, Ortholog, VariantEffectResult } from './types';

export default function App() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<RepairResult[] | null>(null);

  const [currentGene, setCurrentGene] = useState<string>("");
  const [currentEntrezId, setCurrentEntrezId] = useState<string | null>(null);
  const [geneDescription, setGeneDescription] = useState<string | null>(null);

  const [variantEffect, setVariantEffect] = useState<VariantEffectResult | null>(null);
  const [isFetchingEffect, setIsFetchingEffect] = useState(false);

  const [orthologs, setOrthologs] = useState<Ortholog[]>([]);
  const [isFetchingOrthologs, setIsFetchingOrthologs] = useState(false);

  const [residueForDisplay, setResidueForDisplay] = useState<string>("");
  const [mutationForDisplay, setMutationForDisplay] = useState<string>("");

  const handleGenerate = async (geneInput: string, residue: number, mutation: string, oligoLength: number) => {
    setLoading(true);
    setError(null);
    setResults(null);
    setGeneDescription(null);
    setVariantEffect(null);
    setOrthologs([]);
    setCurrentEntrezId(null);

    setCurrentGene(geneInput);
    setResidueForDisplay(residue.toString());
    setMutationForDisplay(mutation);

    try {
      // 1. Fetch Gene Data
      const geneInfo = await resolveGene(geneInput);

      setCurrentGene(geneInfo.symbol);
      setCurrentEntrezId(geneInfo.entrezId || null);
      setGeneDescription(geneInfo.description || null);

      // 2. Fetch Orthologs (Human) & Variant Effects in Parallel
      setIsFetchingOrthologs(true);
      setIsFetchingEffect(true);

      const orthologPromise = fetchOrthologs(geneInfo.symbol, geneInfo.id, geneInfo.entrezId);
      const yeastVepPromise = geneInfo.transcriptId 
          ? fetchVepScore(geneInfo.transcriptId, residue, mutation, geneInfo.sequence)
          : Promise.resolve(null);

      const [orthologsData, yeastEffect] = await Promise.all([orthologPromise, yeastVepPromise]);

      setOrthologs(orthologsData);
      setIsFetchingOrthologs(false);

      // 3. Try to fetch Human AlphaMissense if we have a good ortholog with alignment
      let combinedEffect = yeastEffect;

      if (orthologsData.length > 0) {
          // Find best ortholog that has alignment data and an Ensembl ID
          const bestOrtholog = orthologsData.find(o => o.alignment && o.ensemblId);

          if (bestOrtholog && bestOrtholog.alignment && bestOrtholog.ensemblId) {
             const mapping = mapResidueToOrtholog(residue, bestOrtholog.alignment);

             if (mapping) {
                 // Check conservation (Yeast residue in sequence vs Human residue)
                 // NOTE: We rely on the user input for Yeast residue identity, but strictly we should check geneInfo.sequence[residue-1]
                 // Let's assume user input is correct for the fetch, but for conservation we compare the mapped AA.
                 // Actually, mapResidueToOrtholog returns the Human AA. We need to check if it matches the Yeast AA at that position.
                 const yeastAA = geneInfo.sequence[residue - 1]; // 0-based
                 // Convert 1-letter to check equality
                 const yeastAAChar = yeastAA ? yeastAA.toUpperCase() : '';

                 // If Conserved (Yeast AA === Human AA)
                 if (yeastAAChar === mapping.humanAA.toUpperCase()) {
                     const humanAnalysis = await fetchHumanVariantEffect(
                         bestOrtholog.ensemblId,
                         mapping.humanResidueIndex,
                         mapping.humanAA,
                         mutation // Assume same mutation AA
                     );

                     if (humanAnalysis) {
                         combinedEffect = {
                             ...(combinedEffect || { prediction: 'unknown', source: 'Merged' }),
                             humanAnalysis: humanAnalysis
                         };
                     }
                 }
             }
          }
      }

      setVariantEffect(combinedEffect);
      setIsFetchingEffect(false);

      // 4. Find Sites & Generate Templates
      const sites = findCas9Sites(geneInfo.sequence, residue);

      if (sites.length === 0) {
        throw new Error("No nearby Cas9 target sites found within window.");
      }

      const generatedResults = generateRepairTemplates(
        geneInfo.sequence,
        sites,
        residue,
        mutation,
        oligoLength
      );

      if (generatedResults.length === 0) {
        throw new Error("No sgRNAs available where a silent PAM mutation could be successfully created within the selected oligo length.");
      }

      // Sort
      const getScoreCategory = (score: number) => score >= 70 ? 3 : (score >= 50 ? 2 : 1);
      const getStrategyPriority = (s: string) => (s.includes('PAM') ? 2 : 1);

      generatedResults.sort((a, b) => {
          const catDiff = getScoreCategory(b.score) - getScoreCategory(a.score);
          if (catDiff !== 0) return catDiff;
          const stratDiff = getStrategyPriority(b.strategy) - getStrategyPriority(a.strategy);
          if (stratDiff !== 0) return stratDiff;
          return b.score - a.score;
      });

      setResults(generatedResults);

    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
      setIsFetchingEffect(false);
      setIsFetchingOrthologs(false);
    } finally {
      setLoading(false);
    }
  };

  const renderOrthologs = () => {
      if (isFetchingOrthologs) {
          return (
             <div className="bg-white border border-slate-200 rounded-xl p-4 mb-4 flex items-center gap-3 animate-pulse">
                <div className="h-8 w-8 bg-sky-100 rounded-full"></div>
                <div className="flex-1 space-y-2">
                   <div className="h-3 w-32 bg-slate-200 rounded"></div>
                   <div className="h-2 w-48 bg-slate-100 rounded"></div>
                </div>
             </div>
          );
      }

      if (!results && !loading) return null;
      const hasOrthologs = orthologs.length > 0;
      const dioptLink = currentEntrezId 
        ? `https://www.flyrnai.org/cgi-bin/DRSC_orthologs.pl?sc=1&species=4932&input=${currentEntrezId}`
        : `https://www.flyrnai.org/cgi-bin/DRSC_orthologs.pl?sc=1&species=Yeast&input=${currentGene}`;

      return (
          <div className="bg-sky-50 border border-sky-100 rounded-xl p-5 mb-4 shadow-sm">
              <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                      <div className="p-1.5 bg-sky-100 rounded-lg text-sky-600">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.064M15 20.488V18a2 2 0 012-2h3.064M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                      </div>
                      <div>
                          <h3 className="font-bold text-sky-900 text-sm uppercase tracking-wider">Human Orthologs</h3>
                          <p className="text-xs text-slate-500">Merged from DIOPT & Ensembl</p>
                      </div>
                  </div>
                  <a href={dioptLink} target="_blank" rel="noopener noreferrer" className="text-xs text-sky-600 font-medium hover:underline flex items-center gap-1">
                      View in DIOPT
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                  </a>
              </div>

              <div className="overflow-x-auto max-h-64 overflow-y-auto border rounded-lg border-sky-100">
                {hasOrthologs ? (
                  <table className="w-full text-sm text-left bg-white">
                      <thead className="text-xs text-sky-800 uppercase bg-sky-50 sticky top-0 shadow-sm z-10">
                          <tr>
                              <th className="px-3 py-2">Symbol</th>
                              <th className="px-3 py-2">% Identity</th>
                              <th className="px-3 py-2">% Similarity</th>
                              <th className="px-3 py-2">DIOPT Score</th>
                          </tr>
                      </thead>
                      <tbody>
                          {orthologs.map((orth, idx) => (
                              <tr key={idx} className="border-b border-sky-50 last:border-0 hover:bg-sky-50 transition-colors">
                                  <td className="px-3 py-2 font-bold text-slate-700">
                                      {orth.symbol}
                                      {orth.bestScore && <span className="ml-2 text-[10px] bg-sky-200 text-sky-800 px-1.5 py-0.5 rounded-full" title="Best Score">Best</span>}
                                  </td>
                                  <td className="px-3 py-2 text-slate-600 font-mono">
                                      {orth.percentIdentity ? `${orth.percentIdentity.toFixed(0)}%` : '-'}
                                  </td>
                                  <td className="px-3 py-2 text-slate-600 font-mono">
                                      {orth.percentSimilarity ? `${orth.percentSimilarity.toFixed(0)}%` : '-'}
                                  </td>
                                  <td className="px-3 py-2">
                                      <div className="flex items-center gap-2">
                                         <div className="h-1.5 w-12 bg-slate-200 rounded-full overflow-hidden">
                                             <div className="h-full bg-sky-500" style={{ width: `${Math.min(100, (orth.score / 15) * 100)}%` }}></div>
                                         </div>
                                         <span className="text-xs text-slate-700 font-medium">{orth.score > 0 ? orth.score : '-'}</span>
                                      </div>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
                  ) : (
                      <div className="text-center py-4 text-sm text-slate-500 italic">
                          No orthologs found directly.
                      </div>
                  )}
              </div>
          </div>
      );
  };

  const renderVariantEffectInfo = () => {
      if (isFetchingEffect) {
          return (
             <div className="bg-white border border-slate-200 rounded-xl p-4 mb-8 flex items-center gap-3 animate-pulse">
                <div className="h-10 w-10 bg-indigo-100 rounded-full"></div>
                <div><div className="h-4 w-32 bg-slate-200 rounded mb-2"></div><div className="h-3 w-48 bg-slate-100 rounded"></div></div>
             </div>
          );
      }

      if (!variantEffect) {
          return (
             <div className="bg-slate-50 border border-slate-200 rounded-xl p-5 mb-8 flex items-center gap-4 opacity-75">
                 <div className="p-3 bg-slate-200 rounded-full text-slate-400">
                     <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                 </div>
                 <div>
                     <h4 className="font-bold text-slate-700 text-sm uppercase tracking-wider mb-1">Effect Prediction</h4>
                     <p className="text-sm text-slate-500">
                        No effect scores found for <strong>{currentGene}</strong> p.{residueForDisplay}{mutationForDisplay}.
                     </p>
                 </div>
            </div>
          );
      }

      const { score, prediction, humanAnalysis } = variantEffect;

      // Determine overall status based on Yeast SIFT OR Human AM
      const isYeastDeleterious = (score !== undefined && score <= 0.05) || (prediction && prediction.includes('deleterious'));

      const humanAMScore = humanAnalysis?.amPathogenicity;
      const humanAMClass = humanAnalysis?.amClass;
      const isHumanDeleterious = (humanAMScore !== undefined && humanAMScore >= 0.56) || (humanAMClass && humanAMClass.includes('pathogenic'));

      const isBad = isYeastDeleterious || isHumanDeleterious;

      let colorClass = isBad 
        ? "bg-red-50 border-red-200 text-red-800"
        : "bg-green-50 border-green-200 text-green-800";

      let icon = isBad ? (
         <svg className="w-6 h-6 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
      ) : (
