                     <h4 className="font-bold text-xs uppercase tracking-wider opacity-70 mb-1">Yeast SIFT Score</h4>
                     <div className="flex items-baseline gap-3">
                        {score !== undefined ? (
                            <span className="text-2xl font-bold tracking-tight">{score.toFixed(2)}</span>
