        </div>
      </main>
    </div>
  );
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface PhenotypeAnalysis {
    text: string;
    sources: { uri: string; title: string }[];
}

export async function explorePhenotype(gene: string, phenotype: string): Promise<PhenotypeAnalysis> {
    try {
        const prompt = `
            I am a researcher designing CRISPR point mutations for the S. cerevisiae (yeast) gene ${gene}.

            The user is interested in the phenotype: "${phenotype}".

            This description might be vague. Please search the scientific literature to find:
            1. More specific details related to this phenotype. 
               - If "chemical resistance/sensitivity", find specific chemicals (e.g. Rapamycin, Hydroxyurea, Benomyl) and whether it's resistance or sensitivity.
               - If "temperature", specify the temperatures.
            2. If available, find specific point mutations or domains in ${gene} that are historically known to cause this phenotype.

            Provide a concise summary (max 200 words) that helps narrow down a specific experiment.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
            }
        });

        const text = response.text || "No specific results found. Try refining your query.";

        // Extract sources from grounding metadata
        const rawSources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
            ?.map((c: any) => c.web)
            .filter((w: any) => w && w.uri && w.title) || [];

        // Deduplicate sources by URI
        const uniqueSources = Array.from(new Map(rawSources.map((s: any) => [s.uri, s])).values()) as { uri: string; title: string }[];

        return { text, sources: uniqueSources };
    } catch (error) {
        console.error("GenAI Error:", error);
        throw new Error("Unable to analyze phenotype. Please ensure your API key is configured and try again.");
    }
}

